package com.hospital.management.filter;
import javax.servlet.*;import javax.servlet.annotation.WebFilter;import javax.servlet.http.*;import java.io.IOException;
@WebFilter(urlPatterns={"/dashboard","/admin/*","/doctor/*","/nurse/*","/reception/*","/patient/*","/billing/*","/logout"}) public class AuthenticationFilter implements Filter {public void doFilter(ServletRequest a,ServletResponse b,FilterChain c)throws IOException,ServletException{HttpServletRequest q=(HttpServletRequest)a;HttpServletResponse r=(HttpServletResponse)b;HttpSession s=q.getSession(false);if(s==null||s.getAttribute("authenticatedUser")==null){String target=q.getRequestURI();if(q.getQueryString()!=null)target+="?"+q.getQueryString();s=q.getSession(true);s.setAttribute("requestedUrl",target);r.sendRedirect(q.getContextPath()+"/login");return;}c.doFilter(a,b);}}
